// Carica il database fornitori YEG
const staticData = $getWorkflowStaticData('global');
if (!staticData.suppliers_db) {
  staticData.suppliers_db = { categorie: {}, metadata: { totale_fornitori: 0 } };
}
return $input.all();

// ======= PARSING BRIEF =======
// Struttura il brief e identifica le componenti richieste
const raw = $input.first().json;

const brief = {
  // Identificazione
  submission_id: `SUB-${Date.now()}`,
  data_compilazione: raw.submission_date || new Date().toISOString(),

  // Referente
  nome_referente: `${raw.nome || ''} ${raw.cognome || ''}`.trim(),
  email: raw.email || '',

  // Evento
  nome_evento: raw.nome_evento || '',
  tipologia_evento: raw.tipologia_evento || '',
  data_inizio: raw.data_inizio || '',
  orario_inizio: raw.orario_inizio || '',
  data_fine: raw.data_fine || '',
  orario_fine: raw.orario_fine || '',
  citta: raw.citta || '',
  sede: raw.sede || '',
  numero_partecipanti: parseInt(raw.numero_partecipanti) || 0,
  budget_totale: parseFloat(raw.budget_totale) || 0,

  // Agenda completa
  agenda: raw.agenda || '',

  // --- COMPONENTI ATTIVATE ---
  componenti: {}
};

// Identifica le componenti attive dal form
const componenti = brief.componenti;
const elementiRichiesti = [];

// HOTEL
if (raw.hotel_attivo === 'Sì') {
  componenti.hotel = {
    attivo: true,
    checkin: raw.hotel_checkin || '',
    checkout: raw.hotel_checkout || '',
    camere_singole: parseInt(raw.camere_singole) || 0,
    camere_doppie: parseInt(raw.camere_doppie) || 0,
    totale_camere: (parseInt(raw.camere_singole) || 0) + (parseInt(raw.camere_doppie) || 0),
    note: raw.hotel_note || ''
  };
  elementiRichiesti.push('hotel');
}

// LOCATION
if (raw.location_attiva === 'Sì') {
  componenti.location = {
    attivo: true,
    setup_sala: raw.setup_sala || '',
    setup_av: raw.setup_av || '',
    note: raw.location_note || ''
  };
  elementiRichiesti.push('location');
}

// CATERING (coffee break + pranzo + cena come unica categoria)
const hasCatering = raw.coffee_break_attivo === 'Sì' || raw.pranzo_attivo === 'Sì' || raw.cena_attiva === 'Sì';
if (hasCatering) {
  componenti.catering = {
    attivo: true,
    coffee_break: raw.coffee_break_attivo === 'Sì' ? (raw.coffee_break_note || 'Sì') : null,
    pranzo: raw.pranzo_attivo === 'Sì' ? (raw.pranzo_note || 'Sì') : null,
    cena: raw.cena_attiva === 'Sì' ? (raw.cena_note || 'Sì') : null
  };
  elementiRichiesti.push('catering');
}

// TRASPORTI
if (raw.trasporti_attivi === 'Sì') {
  componenti.trasporti = {
    attivo: true,
    note: raw.trasporti_note || ''
  };
  elementiRichiesti.push('trasporti');
}

// ATTIVITÀ EXTRA / ENTERTAINMENT
if (raw.attivita_extra_attive === 'Sì') {
  componenti.attivita_extra = {
    attivo: true,
    note: raw.attivita_extra_note || ''
  };
  elementiRichiesti.push('entertainment');
}

// SEGRETERIA
if (raw.segreteria === 'Sì') {
  componenti.segreteria = { attivo: true };
}

// APP EVENTO
if (raw.app_evento === 'Sì') {
  componenti.app_evento = { attivo: true };
}

// Se nessun elemento identificato, aggiungi location come default
if (elementiRichiesti.length === 0) {
  elementiRichiesti.push('location');
}

brief.elementi_richiesti = elementiRichiesti;

return { json: brief };

// ======= GENERA PROMPT PER QWEN =======
const brief = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const suppliersDb = staticData.suppliers_db || null;

// --- PRE-FILTRAGGIO FORNITORI YEG ---
let fornitoriYEG = '';
if (suppliersDb && suppliersDb.categorie) {
  const mapCat = {
    'location': ['location'],
    'catering': ['catering', 'ristoranti'],
    'entertainment': ['entertainment'],
    'trasporti': ['trasporti'],
    'hotel': ['hotel']
  };

  const cittaBrief = (brief.citta || '').toLowerCase();
  let sezioni = [];

  for (const elemento of brief.elementi_richiesti) {
    const catKeys = mapCat[elemento] || [elemento];
    for (const catKey of catKeys) {
      const cat = suppliersDb.categorie[catKey];
      if (!cat) continue;

      const match = cat.fornitori.filter(f => {
        const fc = (f.citta || '').toLowerCase();
        if (!fc || !cittaBrief) return false;
        return fc.includes(cittaBrief) || cittaBrief.includes(fc);
      });

      if (match.length > 0) {
        sezioni.push(`\n### ${cat.nome_display} - Fornitori YEG a ${brief.citta}:`);
        match.slice(0, 20).forEach(f => {
          const det = [];
          if (f.capacita) det.push(`Capienza: ${f.capacita}`);
          if (f.prezzo_range) det.push(`Prezzo: ${f.prezzo_range}`);
          if (f.indirizzo) det.push(`Zona: ${f.indirizzo}`);
          if (f.note) det.push(`Note: ${f.note}`);
          sezioni.push(`- ${f.nome}${det.length ? ' | ' + det.join(' | ') : ''}`);
        });
      }
    }
  }

  if (sezioni.length > 0) {
    fornitoriYEG = '\n\n--- FORNITORI YEG (database agenzia) ---' + sezioni.join('\n') + '\n--- FINE FORNITORI YEG ---';
  }
}

// --- COSTRUISCI SEZIONE COMPONENTI ---
const comp = brief.componenti;
let dettaglioComponenti = '';

if (comp.hotel) {
  dettaglioComponenti += `\n\nHOTEL RICHIESTO:\n- Check-in: ${comp.hotel.checkin} | Check-out: ${comp.hotel.checkout}\n- Camere singole: ${comp.hotel.camere_singole} | Doppie: ${comp.hotel.camere_doppie} | Totale: ${comp.hotel.totale_camere}\n- Note: ${comp.hotel.note || 'nessuna'}`;
}

if (comp.location) {
  dettaglioComponenti += `\n\nLOCATION RICHIESTA:\n- Setup sala: ${comp.location.setup_sala}\n- Audio/Video: ${comp.location.setup_av}\n- Note: ${comp.location.note || 'nessuna'}`;
}

if (comp.catering) {
  dettaglioComponenti += `\n\nCATERING RICHIESTO:`;
  if (comp.catering.coffee_break) dettaglioComponenti += `\n- Coffee break/Welcome drink: ${comp.catering.coffee_break}`;
  if (comp.catering.pranzo) dettaglioComponenti += `\n- Pranzo: ${comp.catering.pranzo}`;
  if (comp.catering.cena) dettaglioComponenti += `\n- Cena: ${comp.catering.cena}`;
}

if (comp.trasporti) {
  dettaglioComponenti += `\n\nTRASPORTI RICHIESTI:\n- Note: ${comp.trasporti.note || 'da definire'}`;
}

if (comp.attivita_extra) {
  dettaglioComponenti += `\n\nATTIVITÀ EXTRA / ENTERTAINMENT:\n- Richiesta: ${comp.attivita_extra.note || 'da definire'}`;
}

const prompt = `Sei un senior event planner dell'agenzia YEG Events. Devi elaborare proposte concrete per questo evento corporate.

--- BRIEF EVENTO ---
Referente: ${brief.nome_referente} (${brief.email})
Evento: ${brief.nome_evento}
Tipologia: ${brief.tipologia_evento}
Date: ${brief.data_inizio} ${brief.orario_inizio} → ${brief.data_fine} ${brief.orario_fine}
Città: ${brief.citta}
Sede indicata: ${brief.sede || 'nessuna'}
Partecipanti: ${brief.numero_partecipanti}
Budget totale: ${brief.budget_totale}€

AGENDA PREVISTA:
${brief.agenda}
${dettaglioComponenti}
--- FINE BRIEF ---
${fornitoriYEG}

Genera ESATTAMENTE 10 proposte per OGNUNA di queste categorie: ${brief.elementi_richiesti.join(', ')}

CRITERI DI SELEZIONE:
1. CAPIENZA: deve ospitare ${brief.numero_partecipanti} persone. Per hotel: servono ${comp.hotel ? comp.hotel.totale_camere + ' camere' : 'N/A'}.
2. BUDGET: il budget TOTALE è ${brief.budget_totale}€ per TUTTO l'evento. Distribuisci realisticamente.
3. CITTÀ: ${brief.citta}${brief.sede ? '. Il cliente ha indicato come sede: ' + brief.sede : ''}.
4. SPECIFICHE: rispetta i dettagli (es. setup ${comp.location ? comp.location.setup_sala : ''}, ${comp.catering ? 'servizio catering multi-giorno' : ''}).

REGOLE FORNITORI YEG:
- Includi fornitori YEG SOLO se soddisfano capienza, budget, città e tipo di servizio.
- Non forzare mai un fornitore inadatto. Segnala con is_yeg_supplier: true.
- Completa a 10 con fornitori reali della zona.

Per ogni proposta:
{
  "nome": "Nome reale",
  "descrizione": "Cosa offre (max 100 parole)",
  "motivo_match": "Perché risolve QUESTA specifica esigenza del brief (2-3 frasi concrete)",
  "prezzo_stimato": numero_euro,
  "capacita": "capienza/disponibilità",
  "indirizzo": "indirizzo o zona",
  "punti_forza": ["p1", "p2", "p3"],
  "adeguatezza_budget": 0-100,
  "note": "criticità o info extra",
  "sito_web": "URL",
  "contatto": "tel/email",
  "immagine_url": "URL immagine reale dal sito ufficiale",
  "is_yeg_supplier": true/false
}

Rispondi SOLO con JSON valido:
{
  "categorie": {
    "nome_categoria": {
      "nome_display": "Nome Categoria",
      "budget_allocato": stima_euro,
      "proposte": [ ...10 proposte... ]
    }
  }
}`;

return {
  json: {
    brief: brief,
    prompt: prompt,
    elementi_richiesti: brief.elementi_richiesti
  }
};

