// Parsing risposta QWEN e creazione progetto
const input = $input.first().json;
const brief = $('Genera Prompt AI').first().json.brief;

let proposteAI;
try {
  const content = input.choices[0].message.content;
  proposteAI = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  const content = input.choices[0].message.content;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    proposteAI = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Impossibile estrarre JSON dalla risposta AI: ' + content.substring(0, 200));
  }
}

const progetto = {
  id: `PRJ-${Date.now()}`,
  stato: 'nuovo',
  data_creazione: new Date().toISOString(),
  brief: brief,
  proposte: proposteAI.categorie || proposteAI,
  selezioni_manager: {},
  costi_reali: {},
  note_manager: '',
  storico: [{
    data: new Date().toISOString(),
    azione: 'Progetto creato da brief',
    utente: 'sistema'
  }]
};

return { json: progetto };

// Salva il progetto nello static data
const progetto = $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.progetti) staticData.progetti = {};
if (!staticData.indice_progetti) staticData.indice_progetti = [];

staticData.progetti[progetto.id] = progetto;
staticData.indice_progetti.push({
  id: progetto.id,
  nome_evento: progetto.brief.nome_evento,
  cliente: progetto.brief.nome_referente,
  data_creazione: progetto.data_creazione,
  stato: progetto.stato
});

return { json: { success: true, progetto_id: progetto.id, progetto: progetto } };
